package com.example.cms.attachment;
import com.example.cms.common.response.ApiResponse;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController
public class AttachmentController { private final AttachmentService service; public AttachmentController(AttachmentService service){this.service=service;} @PostMapping("/api/admin/documents/{documentId}/attachments") public ApiResponse<AttachmentDto> upload(@PathVariable Long documentId,@RequestBody Map<String,Object> body)throws Exception{return ApiResponse.ok("첨부파일이 등록되었습니다.",service.register(documentId,String.valueOf(body.get("fileName")),Long.parseLong(String.valueOf(body.getOrDefault("size","0"))),String.valueOf(body.getOrDefault("mimeType","application/octet-stream"))));} @GetMapping("/api/documents/{documentId}/attachments") public ApiResponse<List<AttachmentDto>> list(@PathVariable Long documentId){return ApiResponse.ok("첨부파일 목록",service.list(documentId));} @GetMapping("/api/attachments/{attachmentId}/download") public ApiResponse<AttachmentDto> download(@PathVariable Long attachmentId){return ApiResponse.ok("다운로드 권한 확인",service.get(attachmentId));} @DeleteMapping("/api/admin/attachments/{attachmentId}") public ApiResponse<Void> delete(@PathVariable Long attachmentId){service.delete(attachmentId);return ApiResponse.ok("첨부파일이 삭제되었습니다.",null);} }
